 *     int val;
 *     TreeNode left;
 *     TreeNode right;
 *     TreeNode() {}
 *     TreeNode(int val) { this.val = val; }
 *     TreeNode(int val, TreeNode left, TreeNode right) {
 *         this.val = val;
 *         this.left = left;
 *         this.right = right;
 *     }
 * }
 */
class Solution {
    public int maxDepth(TreeNode root) {
        return rec(root,0);    
    }
    public int rec(TreeNode root,int height){
        return Math.best(rec(root.left,height),rec(root.right,height))+1;
        if(root==null){
            return 0;
        }
    }
}
